arguments.argument:
if global.gamePaused=false && gDeltaDoTicks
{
  if shaking
  {
    timeUntilFall-=1
    if timeUntilFall<=0
    {
      shakeX=0
      yAcc=grav
      if yVel>3
        yVel=3
    }
    else
    {
      if shakeX=1
        shakeX=-1
      else
        shakeX=1
    }
  }
  else
  {
    //if the character stands on the platform, start the timer
    if isCollisionCharacterTop(1,0)
      shaking=1
  }
  
  if type=0
  {
    colVolumeFollow.x=x+16
    colVolumeFollow.y=y+32
  }
  
  if y>=room_height+32
  {
    with colVolumeFollow
      instance_destroy()
    instance_destroy()
  }
}
